window.__QUIZ_DATA__=[{"id":"objective>Biology>1997>1","subject":"Biology","year":"1997","type":"Objective","topic":"CONCEPT OF LIVING : CLASSIFICATION","question":"Which of the following organism possesses both plant and animal characteristics?","images":[],"options":{"A":"Amoeba","B":"Paramecium","C":"Euglena","D":"Mucor"},"answer":"C","explanation":"Euglena is a genus of single-celled flagellate eukaryotes. It is the best known and most widely studied member of the class Euglenoidea, a diverse group containing some 54 genera and at least 800 species. Species of Euglena are found in fresh and salt waters. They are often abundant in quiet inland waters where they may bloom in numbers sufficient to color the surface of ponds and ditches green (Euglena viridis) or red (Euglena sanguinea). The species possess both plant and animal characteristics. As a plant, it can photosynthesize and as an animal, it can move around in search of food using its flagella.","marks":"1","difficulty":"1"},{"id":"objective>Biology>1997>2","subject":"Biology","year":"1997","type":"Objective","topic":"CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.","question":"The structure represented in the diagram above is","images":["data:image/png;base64,"],"options":{"A":"a colony","B":"a tissue","C":"a filament","D":"a pseudopodium"},"answer":"C","explanation":"The structure represented in the diagram above is a filament. Spirogyras are filamentous green algae, named for their spiraling chloroplasts. Each cell of the filaments features a large central vacuole, within which the nucleus is suspended by fine strands of cytoplasm","marks":"1","difficulty":"2"},{"id":"objective>Biology>1997>3","subject":"Biology","year":"1997","type":"Objective","topic":"CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.","question":"The part labelled I in the diagram is the","images":["data:image/png;base64,"],"options":{"A":"cytoplasm","B":"chloroplast","C":"chlorophyll","D":"nucleus"},"answer":"B","explanation":"The part labelled I in the diagram is the chloroplast. chloroplast, structure within the cells of plants and green algae that is the site of photosynthesis, the process by which light energy is converted to chemical energy, resulting in the production of oxygen and energy-rich organic compounds.","marks":"1","difficulty":"1"},{"id":"objective>Biology>1997>4","subject":"Biology","year":"1997","type":"Objective","topic":"CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.","question":"What is the function of the part labelled II in the diagram? It","images":["data:image/png;base64,"],"options":{"A":"manufactures food","B":"protects the chloroplast","C":"produces protein","D":"suspends the nucleus"},"answer":"D","explanation":"The cytoplasm surrounds and supports the nucleus along with other organelles, ensuring they remain in place and can function properly within the cell. This suspension also allows for the distribution of nutrients and waste products within the cell.  The Other Options Are Incorrect  Manufactures food: This function is specific to chloroplasts, which are the site of photosynthesis.  Protects the chloroplast: This role is generally associated with the cell wall or cell membrane, which encases the entire cell, including the chloroplasts.  Produces protein: Ribosomes are the primary site for protein synthesis, not the cytoplasm itself.  Digests starch: This function is associated with amyloplasts, which are specialized for storing and converting starch.  Therefore, based on the structure and function of the cytoplasm, Suspends the nucleus is the correct answer.","marks":"1","difficulty":"2"},{"id":"objective>Biology>1997>5","subject":"Biology","year":"1997","type":"Objective","topic":"CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.","question":"Which of the following organelles helps to remove excess water from cells?","images":[],"options":{"A":"Mitochondrion","B":"Ribosome","C":"Contractile vacuole","D":"Golgi body"},"answer":"C","explanation":"The contractile vacuole is an organelle in certain cells, particularly in protozoa, that expels excess water out of the cell. It performs osmoregulation, the process of regulating water potential in order to keep fluid and electrolyte balance within the cell. The other options, Mitochondrion, Ribosome, and Golgi body, do not perform this function. Mitochondrion is involved in energy production, Ribosome in protein synthesis, and Golgi body in processing and packaging proteins.","marks":"1","difficulty":"1"},{"id":"objective>Biology>1997>6","subject":"Biology","year":"1997","type":"Objective","topic":"CONCEPT OF LIVING : THE CELL AND ITS ENVIRONMENT","question":"Which of the following processes occurs by diffusion?","images":[],"options":{"A":"Reabsorption of water in kidney tubules","B":"Entry of water into the cytoplasm of unicellular animals","C":"Absorption of water in the large intestine","D":"Exchange of nutrients between a mother and the foetus"},"answer":"D","explanation":"Certain nutrients and gases like oxygen and carbon dioxide do indeed move by simple diffusion across the placental barrier. This passive movement is from areas of higher concentration to lower concentration. Thus, given that simple diffusion is involved in the exchange of some nutrients and gases (like oxygen and carbon dioxide) between the mother and the foetus is correct.","marks":"1","difficulty":"2"},{"id":"objective>Biology>1997>7","subject":"Biology","year":"1997","type":"Objective","topic":"MICROORGANISMS: MAN AND HEALTH : MICROORGANISMS IN ACTION","question":"Which of the following is a product of brewing when yeast is used as a fermenting agent?","images":[],"options":{"A":"Nitrogen","B":"Oxygen","C":"Malt","D":"Ethanol"},"answer":"D","explanation":"The process of brewing involves the fermentation of sugars by yeast. The yeast consumes the sugars and produces ethanol and carbon dioxide as by-products. Therefore, the product of brewing when yeast is used as a fermenting agent is ethanol.","marks":"1","difficulty":"1"},{"id":"objective>Biology>1997>8","subject":"Biology","year":"1997","type":"Objective","topic":"CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS","question":"Which of the following hind limb bones is equivalent to the humerus of the forelimb?","images":[],"options":{"A":"Patella","B":"Tarsal","C":"Tibia","D":"Femur"},"answer":"D","explanation":"The humerus is the single long bone of the upper arm in the forelimb. The femur is the single long bone of the upper leg (thigh) in the hind limb. These bones are structurally and functionally analogous: Both are the longest bones in their respective limbs. Both articulate with the bones of the lower segment (radius/ulna in the forelimb and tibia/fibula in the hind limb).Both are involved in similar functions related to movement and support. Thus, the femur is the hind limb bone equivalent to the humerus in the forelimb.","marks":"1","difficulty":"1"},{"id":"objective>Biology>1997>9","subject":"Biology","year":"1997","type":"Objective","topic":"CONCEPT OF LIVING : EXCRETORY SYSTEMS","question":"Clotting of blood is a function of","images":[],"options":{"A":"vitamin C","B":"vitamin K","C":"vitamin B2","D":"vitamin E"},"answer":"B","explanation":"Clotting of blood is a function of Vitamin K. Vitamin K is a fat-soluble vitamin that plays a key role in helping the blood clot, preventing excessive bleeding. Unlike many other vitamins, vitamin K is not typically used as a dietary supplement. Vitamin K is actually a group of compounds. The most important of these compounds appears to be vitamin K1 and vitamin K2. Vitamin K1 is obtained from leafy greens and some other vegetables. Vitamin K2 is a group of compounds largely obtained from meats, cheeses, and eggs, and synthesized by bacteria.","marks":"1","difficulty":"1"},{"id":"objective>Biology>1997>10","subject":"Biology","year":"1997","type":"Objective","topic":"CONCEPT OF LIVING : RESPIRATORY SYSTEM","question":"Which of the following structures is associated with respiration in insects?","images":[],"options":{"A":"Air sac","B":"Spiracle","C":"Lung","D":"Alveolus"},"answer":"B","explanation":"Spiracles are small openings located on the sides of an insect's body. They are the entry and exit points for air in the tracheal system. Air enters the spiracles, moves through the tracheae, and diffuses directly into the insect's tissues. Spiracles are crucial because they control the opening and closing to regulate air flow and water loss. The tracheal system directly delivers oxygen to tissues and removes carbon dioxide, which is different from the circulatory system used in vertebrates.","marks":"1","difficulty":"2"},{"id":"objective>Biology>1997>11","subject":"Biology","year":"1997","type":"Objective","topic":"CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS","question":"The diagram below represents a section of the stem of a plant, use it to answer the question       Which of the labelled parts is made up of dead cells?","images":["data:image/png;base64,"],"options":{"A":"III and IV","B":"I, II and IV","C":"IV and V","D":"II and III"},"answer":"A","explanation":"II: Cortex - composed of parenchyma cells, generally living cells.  III: Vascular bundle - includes both xylem (often dead at maturity) and phloem (living cells).  IV: Xylem - made up of dead cells that provide support and transport water and minerals.    Thus, the most accurate option is: III and IV, since the vascular bundle (III) includes xylem, which is made up of dead cells, and xylem (IV) itself is dead.","marks":"1","difficulty":"2"},{"id":"objective>Biology>1997>12","subject":"Biology","year":"1997","type":"Objective","topic":"CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS","question":"The diagram below represents a section of the stem of a plant, use it to answer the question     The part labelled I in the diagram is called","images":["data:image/png;base64,"],"options":{"A":"stoma","B":"epidermis","C":"lenticel","D":"cortex"},"answer":"C","explanation":"The part labelled I in the diagram is called Ienticel. A lenticel is a porous tissue made up of vast intercellular gaps between cells. On stems and roots, lenticels appear as elevated circular, oval, or elongated patches","marks":"1","difficulty":"2"},{"id":"objective>Biology>1997>13","subject":"Biology","year":"1997","type":"Objective","topic":"CONCEPT OF LIVING : EXCRETORY SYSTEMS","question":"The malpighian tubule plays a major role in","images":[],"options":{"A":"inspiration","B":"digestion","C":"secretion","D":"excretion"},"answer":"D","explanation":"The malpighian tubule plays a major role in excretion. Malpighian tubules are excretory systems found in insects, located in the abdominal body cavity and draining between the midgut and hindgut","marks":"1","difficulty":"1"},{"id":"objective>Biology>1997>14","subject":"Biology","year":"1997","type":"Objective","topic":"CONCEPT OF LIVING : TRANSPORT SYSTEM","question":"Filtered blood from the kidney is carried back to the circulatory system through the","images":[],"options":{"A":"hepatic portal vein","B":"renal artery","C":"renal vein","D":"pulmonary vein"},"answer":"C","explanation":"The renal vein is the blood vessel that carries filtered blood away from the kidney and back into the circulatory system. After the blood has been filtered in the nephrons of the kidney, it is collected in the renal vein. This vein then carries the filtered blood back to the inferior vena cava, which then takes the blood to the heart for re-oxygenation and distribution to the rest of the body. The other options are incorrect because the hepatic portal vein carries blood from the gastrointestinal tract to the liver, the renal artery carries unfiltered blood to the kidney, and the pulmonary vein carries oxygenated blood from the lungs to the heart.","marks":"1","difficulty":"1"},{"id":"objective>Biology>1997>15","subject":"Biology","year":"1997","type":"Objective","topic":"CONCEPT OF LIVING : HORMONAL COORDINATION","question":"The early removal of the pituary gland in animals may cause","images":[],"options":{"A":"ceasation of growth","B":"gigantism","C":"poor mental development","D":"goitre"},"answer":"A","explanation":"The pituitary gland is a small pea-sized gland that plays a major role in regulating vital body functions and general wellbeing. It is referred to as the body's 'master gland' because it controls the activity of most other hormone-secreting glands. One of the hormones it produces is the growth hormone, which is essential for growth and development. If the pituitary gland is removed early in life, the production of growth hormone will cease, leading to stunted growth or cessation of growth.","marks":"1","difficulty":"2"},{"id":"objective>Biology>1997>16","subject":"Biology","year":"1997","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : HABITATS","question":"A high concentration of auxin in the root will","images":[],"options":{"A":"inhibit growth","B":"stimulate growth","C":"not affect growth","D":"cause the root to rot"},"answer":"A","explanation":"Auxin is a type of plant hormone that plays a crucial role in the growth and behavior of plants. It is primarily involved in cell elongation, but its effects can vary depending on the concentration and location within the plant. In the roots, a high concentration of auxin inhibits growth, while a low concentration promotes it. This is because auxin concentration in the root is inversely proportional to the rate of cell division and elongation. Therefore, a high concentration of auxin in the root will inhibit growth.","marks":"1","difficulty":"1"},{"id":"objective>Biology>1997>17","subject":"Biology","year":"1997","type":"Objective","topic":"CONCEPT OF LIVING : NERVOUS COORDINATION","question":"The part labelled II in the diagram is the","images":["data:image/jpeg;base64,"],"options":{"A":"central canal","B":"grey matter","C":"spinal cord","D":"dorsal root"},"answer":"B","explanation":"Grey matter: This is the butterfly-shaped area in the center of the spinal cord.","marks":"1","difficulty":"2"},{"id":"objective>Biology>1997>18","subject":"Biology","year":"1997","type":"Objective","topic":"CONCEPT OF LIVING : NERVOUS COORDINATION","question":"Which of the labelled parts is filled with cerebrospinal fluid?","images":["data:image/png;base64,"],"options":{"A":"V and I","B":"I only","C":"III only","D":"II and I"},"answer":"B","explanation":"Cerebrospinal Fluid (CSF): The CSF primarily fills the central canal of the spinal cord and the subarachnoid space surrounding the brain and spinal cord.  Correct Identifications: I (Central canal): Filled with cerebrospinal fluid.","marks":"1","difficulty":"1"},{"id":"objective>Biology>1997>19","subject":"Biology","year":"1997","type":"Objective","topic":"CONCEPT OF LIVING : NERVOUS COORDINATION","question":"Which of the following is an example of a reflex action?","images":[],"options":{"A":"Sneezing","B":"Biting","C":"Dancing","D":"Singing"},"answer":"A","explanation":"A reflex action is an involuntary and nearly instantaneous movement in response to a stimulus. Sneezing is a reflex action because it is an automatic response of the body to foreign particles in the nose. Biting, dancing, and singing are not reflex actions because they are voluntary actions that are under conscious control.","marks":"1","difficulty":"1"},{"id":"objective>Biology>1997>20","subject":"Biology","year":"1997","type":"Objective","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.","question":"During mating, the male toad holds the female with its?","images":[],"options":{"A":"sticky tongue","B":"jelly","C":"webbed hind limbs","D":"nuptial pad"},"answer":"D","explanation":"During mating, the male toad holds the female with its nuptial pad. The nuptial pad is a gland. It is a secondary sex characteristic. The male animals use the nuptual pad to hold on to females when they mate, but it does not make or move sperm itself.","marks":"1","difficulty":"1"},{"id":"objective>Biology>1997>21","subject":"Biology","year":"1997","type":"Objective","topic":"CONCEPT OF LIVING : REPRODUCTION","question":"The diagram above represents a?","images":["data:image/png;base64,"],"options":{"A":"germinating seed","B":"radicle","C":"shoot showing negative phototropism","D":"germinating pollen grain"},"answer":"D","explanation":"The diagram above represents a germinating pollen grain. The germination of pollen grains begins by absorption of water and nutrients and the pollen grain produces a tiny pollen tube through the style to the ovary. The tube cell enlarges and comes out of the pollen grain through one of the germ pores to form a pollen tube.The tube nucleus descends to the tip of the pollen tube.","marks":"1","difficulty":"2"},{"id":"objective>Biology>1997>22","subject":"Biology","year":"1997","type":"Objective","topic":"CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.","question":"The part labelled I in the diagram is the","images":["data:image/png;base64,"],"options":{"A":"cytoplasm","B":"pollen nucleus","C":"pollen tube","D":"exine"},"answer":"D","explanation":"The part labelled I in the diagram, which is the outermost layer of the pollen grain, must be the exine.  Cytoplasm: This is the gel-like substance within the cell membrane that contains all organelles and cell parts. It is not a structure that forms a distinct outer layer.  Pollen nucleus: This is located inside the pollen grain and is involved in fertilization. It is not a structural component seen from the outside.  Pollen tube: This is a structure that forms during the germination of pollen and grows towards the ovule for fertilization. It is not visible in a simple diagram of a pollen grain before germination.","marks":"1","difficulty":"2"},{"id":"objective>Biology>1997>23","subject":"Biology","year":"1997","type":"Objective","topic":"PLANT AND ANIMAL NUTRITION : PLANT NUTRITION","question":"Which of the following fruits is a schizocarp?","images":[],"options":{"A":"Groundnut","B":"Desmodium","C":"crotalaria","D":"Cashew"},"answer":"B","explanation":"A schizocarp is a type of dry fruit that splits into two or more parts (called mericarps) at maturity, but the parts remain attached to each other. Desmodium is a type of plant that produces schizocarp fruits. Groundnut, crotalaria, and cashew do not produce schizocarp fruits.","marks":"1","difficulty":"2"},{"id":"objective>Biology>1997>24","subject":"Biology","year":"1997","type":"Objective","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.","question":"Which of the following is not a characteristic of wind dispersed fruits and seeds?","images":[],"options":{"A":"Light weight","B":"Wing","C":"Floss","D":"Stickyjuice"},"answer":"D","explanation":"Wind dispersed fruits and seeds have certain characteristics that enable them to be carried by the wind. These include being lightweight, having wings or other structures to catch the wind (like floss), and being dry. Sticky juice is not a characteristic of wind dispersed fruits and seeds because it would make them heavier and stick to surfaces, preventing them from being carried by the wind. Therefore, the correct answer is 'Sticky juice'.","marks":"1","difficulty":"1"},{"id":"objective>Biology>1997>25","subject":"Biology","year":"1997","type":"Objective","topic":"CONCEPT OF LIVING : TRANSPORT SYSTEM","question":"Which of the following structures transports water from the roots to the leaves?","images":[],"options":{"A":"Phloem","B":"Cambium","C":"Pericycle","D":"Xylem"},"answer":"D","explanation":"The structure that transports water from the roots to the leaves is the Xylem. Xylem is one of the two types of transport tissue in vascular plants, phloem being the other. The basic function of xylem is to transport water from roots to stems and leaves, but it also transports nutrients. Phloem, on the other hand, is the living tissue that transports the soluble organic compounds made during photosynthesis and known as photosynthates, in particular, sugar, from leaves where they are produced by photosynthesis to rest of the plant. Cambium is a type of plant tissue located between the xylem and the phloem in the stem and root of a vascular plant, and is the part of the plant where growth takes place. Pericycle is a thin layer of plant tissue between the endodermis and the phloem and is responsible for the production of lateral roots.","marks":"1","difficulty":"2"},{"id":"objective>Biology>1997>26","subject":"Biology","year":"1997","type":"Objective","topic":"CONCEPT OF LIVING : SENSE ORGANS","question":"The eye defect represented in the diagram is?","images":["data:image/png;base64,"],"options":{"A":"myopia","B":"hypermetropia","C":"presbyopia","D":"astigmatism"},"answer":"A","explanation":"Nearsightedness (myopia) is a common vision condition in which near objects appear clear, but objects farther away look blurry.","marks":"1","difficulty":"2"},{"id":"objective>Biology>1997>27","subject":"Biology","year":"1997","type":"Objective","topic":"CONCEPT OF LIVING : SENSE ORGANS","question":"The above defect is corrected by using a?","images":["data:image/png;base64,"],"options":{"A":"concave lens","B":"converging lens","C":"cylindrical lens","D":"bi-focal lens"},"answer":"A","explanation":"They are concave-shaped and help the eyes focus light properly.","marks":"1","difficulty":"1"},{"id":"objective>Biology>1997>28","subject":"Biology","year":"1997","type":"Objective","topic":"CONCEPT OF LIVING : REPRODUCTIVE SYSTEM OF MAMMALS","question":"Which of the following organisms is viviparous?","images":[],"options":{"A":"Tapeworm","B":"Snail","C":"Sheep","D":"Grasshopper"},"answer":"C","explanation":"Viviparous organisms are those that give birth to live young ones instead of laying eggs. Among the options provided, only sheep fall under this category. Tapeworms, snails, and grasshoppers are all oviparous, meaning they lay eggs.","marks":"1","difficulty":"2"},{"id":"objective>Biology>1997>29","subject":"Biology","year":"1997","type":"Objective","topic":"PLANT AND ANIMAL NUTRITION : NITROGEN CYCLE","question":"The reduction of nitrates to gaseous nitrogen is","images":[],"options":{"A":"nitrogen fixing","B":"nitrogen cycle","C":"ammonification","D":"denitrification"},"answer":"D","explanation":"The reduction of nitrates to gaseous nitrogen is denitrification. Denitrification is the process that converts nitrate to nitrogen gas, thus removing bioavailable nitrogen and returning it to the atmosphere.","marks":"1","difficulty":"2"},{"id":"objective>Biology>1997>30","subject":"Biology","year":"1997","type":"Objective","topic":"ECOLOGICAL MANAGEMENT : BIOLOGICAL ASSOCIATIONS","question":"The association between protozoa and termites is an example of","images":[],"options":{"A":"symbiosis","B":"parasitism","C":"predation","D":"saprophytism"},"answer":"A","explanation":"The association between protozoa and termites is an example of symbiosis. A symbiosis is an evolved interaction or close living relationship between organisms from different species, usually with benefits to one or both of the individuals involved.","marks":"1","difficulty":"2"},{"id":"objective>Biology>1997>31","subject":"Biology","year":"1997","type":"Objective","topic":"CONCEPT OF LIVING : CLASSIFICATION","question":"Flatworms are classified as","images":[],"options":{"A":"Platyhelminthes","B":"coelenlerata","C":"annelida","D":"nematoda"},"answer":"A","explanation":"Flatworms are classified as Platyhelminthes. The phylum Platyhelminthes consists of simple worm-like animals called flatworms. Platyhelminthes have the following important characteristics: They are triploblastic, acoelomate, and bilaterally symmetrical.","marks":"1","difficulty":"1"},{"id":"objective>Biology>1997>32","subject":"Biology","year":"1997","type":"Objective","topic":"CONCEPT OF LIVING : REPRODUCTIVE SYSTEM OF MAMMALS","question":"The essential parts of a flower are","images":[],"options":{"A":"petals and sepals","B":"anther and filament","C":"stigma and style","D":"androecium and gynoecium"},"answer":"D","explanation":"The essential parts of a flower are androecium and gynoecium. Androecium and gynoecium are the two, opposite reproductive organs of the flower, the sexual reproductive structures in angiosperms. Androecium is also called stamens, which comprises of anther and filaments while gynoecium is also called the pistil or carpel, which comprises of stigma, style, and ovary.","marks":"1","difficulty":"1"},{"id":"objective>Biology>1997>33","subject":"Biology","year":"1997","type":"Objective","topic":"CONCEPT OF LIVING : EXCRETORY SYSTEMS","question":"Which of the following parts of the tooth is first damaged during dental decay?","images":[],"options":{"A":"Cement","B":"Enamel","C":"Dentine","D":"Root"},"answer":"B","explanation":"Tooth decay begins when bacteria in your mouth make acids that attack the tooth's surface (enamel). This can lead to a small hole in a tooth, called a cavity.","marks":"1","difficulty":"1"},{"id":"objective>Biology>1997>34","subject":"Biology","year":"1997","type":"Objective","topic":"CONCEPT OF LIVING : THE CELL AND ITS ENVIRONMENT","question":"The set- up above is used to demonstrate","images":["data:image/png;base64,"],"options":{"A":"plasmolysis","B":"osmosis","C":"suction pressure","D":"fermentation"},"answer":"D","explanation":"Fermentation: Fermentation involves the conversion of sugars into alcohol or acids by microorganisms like yeast. Test tube A contains 5% sucrose solution and yeast, which are ideal conditions for fermentation. The yeast will metabolize the sugars in the sucrose solution and produce carbon dioxide gas and alcohol (in the case of yeast fermentation).    Given the description that test tube A contains yeast and a sugar solution (5% sucrose), this is indeed indicative of a setup used to demonstrate fermentation","marks":"1","difficulty":"2"},{"id":"objective>Biology>1997>35","subject":"Biology","year":"1997","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : MICROORGANISMS: MAN AND HIS HEALTH.","question":"What will be the colour of the solution in the test tube labelled II at the end of the experiment?","images":["data:image/png;base64,"],"options":{"A":"Pink","B":"Yellow","C":"Milky","D":"Reddish white"},"answer":"C","explanation":"At the end of the experiment, the solution in test tube II (the lime water) will turn milky or cloudy due to the presence of carbon dioxide gas produced during fermentation in test tube A    The other options are not correct:  Pink: There is no indication that the solution will turn pink.  Yellow: Lime water is normally colorless, and the reaction with carbon dioxide does not produce a yellow color.  Reddish white: This color change is not associated with the reaction between carbon dioxide and lime water.","marks":"1","difficulty":"2"},{"id":"objective>Biology>1997>36","subject":"Biology","year":"1997","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : MICROORGANISMS: MAN AND HIS HEALTH.","question":"Which gas will pass into the test tube labelled II from I?","images":["data:image/png;base64,"],"options":{"A":"Carbon monoxide","B":"Carbon dioxide","C":"Oxygen","D":"Ammonia"},"answer":"B","explanation":"The experiment is designed to demonstrate fermentation, which produces carbon dioxide gas as a byproduct. The carbon dioxide gas produced in test tube A (where the yeast is fermenting the sucrose) will pass through the U-tube and into test tube II (containing lime water).    Carbon monoxide: This gas is not produced during fermentation.    Oxygen: While oxygen may be present in the air, it is not the gas produced during fermentation that passes into test tube II.    Ammonia: This gas is not produced during fermentation.","marks":"1","difficulty":"2"},{"id":"objective>Biology>1997>37","subject":"Biology","year":"1997","type":"Objective","topic":"PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION","question":"In which of these forms is carbohydrate stored in yam?","images":[],"options":{"A":"Glucose","B":"Maltose","C":"Starch","D":"Glycogen"},"answer":"C","explanation":"Carbohydrates in yams are stored in the form of starch. Starch is a polysaccharide carbohydrate consisting of a large number of glucose units joined together by glycosidic bonds. This polysaccharide is produced by most green plants as energy storage. It is the most common carbohydrate in human diets and is contained in large amounts in staple foods like potatoes, wheat, maize (corn), rice, and cassava.","marks":"1","difficulty":"1"},{"id":"objective>Biology>1997>38","subject":"Biology","year":"1997","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : HABITATS","question":"Northern Guinea savanna is associated with","images":[],"options":{"A":"abundant rainfall","B":"abundant trees and shrubs","C":"soil with very little plant cover","D":"abundant grasses"},"answer":"D","explanation":"Northern Guinea savanna is associated with abundant grasses. The Guinea savanna is a type of grassland with scattered trees and shrubs, which can be found between the rain forest and desert. The vegetation of the Guinea savanna is interspersed with trees such as baobabs and acacias, and grasses and herbs are abundant. The grasses found in the savanna are tall and coarse and are interspersed with areas of woodland and tall vegetation.","marks":"1","difficulty":"2"},{"id":"objective>Biology>1997>39","subject":"Biology","year":"1997","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : POPULATION STUDIES BY SAMPLING","question":"Which of the following activities is not necessary in population sampling?","images":[],"options":{"A":"Selecting the habitat","B":"Dividing the selected habitat into portions","C":"Throwing the quadrat randomly","D":"Feeding the organisms"},"answer":"D","explanation":"Population sampling is a method used in ecology to measure the abundance and distribution of a particular species within a specified area. The process involves selecting the habitat, dividing the selected habitat into portions, and throwing the quadrat randomly. However, feeding the organisms is not a necessary activity in population sampling. It does not contribute to the measurement of the species' abundance or distribution.","marks":"1","difficulty":"1"},{"id":"objective>Biology>1997>40","subject":"Biology","year":"1997","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL FACTORS","question":"Which of the following is an abiotic factor?","images":[],"options":{"A":"Predation","B":"Rainfall","C":"Cropping","D":"Grazing"},"answer":"B","explanation":"Abiotic factors are non-living physical and chemical elements in the ecosystem. They can influence living organisms in terms of growth, development, and distribution. Examples of abiotic factors include sunlight, temperature, wind, water, soil, and rainfall. Therefore, rainfall is an abiotic factor. Predation, cropping, and grazing are biotic factors as they involve interactions between living organisms.","marks":"1","difficulty":"1"},{"id":"objective>Biology>1997>41","subject":"Biology","year":"1997","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : SIMPLE MEASUREMENT OF ECOLOGICAL FACTORS","question":"The maximum and minimum thermometer is used to measure","images":[],"options":{"A":"light intensity","B":"highest and lowest temperature of the day","C":"atmospheric pressure","D":"highest and lowest amount of rainfall in a month"},"answer":"B","explanation":"A maximum and minimum thermometer, also known as a Six's thermometer, is a thermometer which registers the maximum and minimum temperatures reached over a period of time, typically 24 hours. It is used to record the extremes of temperature at a location, for instance in meteorology and horticulture. It is not used to measure light intensity, atmospheric pressure or rainfall.","marks":"1","difficulty":"1"},{"id":"objective>Biology>1997>42","subject":"Biology","year":"1997","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : FOOD WEBS AND TROPHIC LEVELS","question":"Which of the following organisms will have the highest biomass?","images":[],"options":{"A":"Small fish","B":"Tadpole","C":"Hawk","D":"Phytoplankton"},"answer":"D","explanation":"In an ecological pyramid, biomass decreases as we move from the producers to the top carnivores. Phytoplankton, being the primary producers in aquatic ecosystems, have the highest biomass. Hawks, being top carnivores, have the least biomass. Small fish and tadpoles, being in the middle of the food chain, have less biomass than phytoplankton but more than hawks.","marks":"1","difficulty":"2"},{"id":"objective>Biology>1997>43","subject":"Biology","year":"1997","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : NUTRIENT CYCLING IN NATURE","question":"Which of the following is the correct sequence for energy transfer and nutrient cycling among living things in an ecosystem?","images":[],"options":{"A":"Consumers \u2192 producers \u2192 decomposers","B":"Producers \u2192 decomposers \u2192 consumers","C":"Decomposers \u2192 producers \u2192 consumers","D":"Producers \u2192 consumers \u2192 decomposers"},"answer":"D","explanation":"In an ecosystem, the energy transfer and nutrient cycling among living things follow the sequence: Producers \u2192 consumers \u2192 decomposers. Producers, such as plants, produce their own food through photosynthesis. Consumers, such as animals, consume the producers for energy. Decomposers, such as fungi and bacteria, break down dead or decaying organisms, returning nutrients back to the environment for use by producers.","marks":"1","difficulty":"2"},{"id":"objective>Biology>1997>44","subject":"Biology","year":"1997","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL FACTORS","question":"Which of the following factors does not affect the distribution of organisms in an aquatic habitat?","images":[],"options":{"A":"Turbidity","B":"Depth of water","C":"Humidity","D":"Temperature"},"answer":"C","explanation":"Humidity does not affect the distribution of organisms in an aquatic habitat. Humidity refers to the amount of water vapor in the air, which is more relevant to terrestrial habitats. In contrast, factors like turbidity (cloudiness of the water), depth of water, and temperature can significantly influence the types of organisms that can survive in an aquatic habitat.","marks":"1","difficulty":"2"},{"id":"objective>Biology>1997>45","subject":"Biology","year":"1997","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : HABITATS","question":"A habitat with low rainfall, very low humidity, exposed soil with little plant cover, few trees and shrubs is likely to be","images":[],"options":{"A":"a rain forest","B":"a mangrove forest","C":"a desert","D":"a swamp"},"answer":"C","explanation":"A habitat with low rainfall, very low humidity, exposed soil with little plant cover, few trees and shrubs is likely to be a desert. Deserts are characterized by extremely low rainfall, low humidity, and sparse vegetation due to the harsh climatic conditions.","marks":"1","difficulty":"2"},{"id":"objective>Biology>1997>46","subject":"Biology","year":"1997","type":"Objective","topic":"ECOLOGY OF POPULATION : FACTORS THAT AFFECT POPULATION","question":"Which of the following factors may not cause over-crowding?","images":[],"options":{"A":"Limited space","B":"Scarcity of food","C":"Reduced birth rate","D":"Lose immigration conditions"},"answer":"C","explanation":"Overcrowding is typically caused by factors that increase the population density in a given area. These factors can include limited space, scarcity of food, and loose immigration conditions, which can all lead to an increase in the number of individuals in a given area. However, a reduced birth rate would not cause overcrowding. In fact, it would likely alleviate overcrowding, as fewer individuals are being added to the population.","marks":"1","difficulty":"2"},{"id":"objective>Biology>1997>47","subject":"Biology","year":"1997","type":"Objective","topic":"PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION","question":"Crops grown mainly to feed animals are called","images":[],"options":{"A":"forage crops","B":"fibre crops","C":"wood crops","D":"oil crops"},"answer":"A","explanation":"Crops grown mainly to feed animals are called forage crops. Forage crops are crops on which animals graze independently \u2013 they are grown specifically to be grazed by livestock or conserved as hay or silage.","marks":"1","difficulty":"1"},{"id":"objective>Biology>1997>48","subject":"Biology","year":"1997","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : RELEVANCE OF BIOLOGY TO AGRICULTURE","question":"The farming practice by which an exhausted farm land is left for a number of years before cultivation is known as","images":[],"options":{"A":"crop rotation","B":"continuous cropping","C":"monocropping","D":"bush fallowing"},"answer":"D","explanation":"Bush fallowing is a farming method, where a piece of land is cultivated for several years and left to fallow or rest of some years to allow it regain its fertility.","marks":"1","difficulty":"1"},{"id":"objective>Biology>1997>49","subject":"Biology","year":"1997","type":"Objective","topic":"MICROORGANISMS: MAN AND HEALTH : MICROORGANISMS IN ACTION","question":"In palm-wine, yeast acts as a","images":[],"options":{"A":"carrier","B":"culturing agent","C":"preservative","D":"catalyst"},"answer":"D","explanation":"A catalyst is a substance that speeds up a chemical reaction without undergoing any permanent change itself.Yeast population, among other organisms, have been found to vary in palm wine depending on the source. The yeasts quantitatively convert the sugars in the palm wine into alcohol. Hence, the physicochemical condition of palm wine is a function of the metabolic activities of the inherent yeasts in palm wine.","marks":"1","difficulty":"1"},{"id":"objective>Biology>1997>50","subject":"Biology","year":"1997","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL MANAGEMENT","question":"Which of the following farm practices can cause loss of soil fertility?","images":[],"options":{"A":"Mulching","B":"Compost application","C":"Use of fertilizers","D":"intensive cropping"},"answer":"D","explanation":"Intensive cropping can cause loss of soil fertility. Intensive cropping, also known as intensive agriculture, is a type of agricultural practice where a lot of labor and capital are used to increase the yield or output from a given area of land. This practice often involves the use of high amounts of fertilizers and pesticides, which can lead to soil degradation and loss of soil fertility over time. The other options like mulching, compost application, and use of fertilizers are practices that improve soil fertility.","marks":"1","difficulty":"2"},{"id":"objective>Biology>1997>51","subject":"Biology","year":"1997","type":"Objective","topic":"APPLICATION OF VARIATIONS :","question":"One of the use of variation is in","images":[],"options":{"A":"determining the size and weight of an individual","B":"determining paternity","C":"conservation of wildlife","D":"controlling of disease vector"},"answer":"B","explanation":"Variation is a fundamental aspect of life because it results in the differences between individuals of the same species. It can be used in determining paternity. This is because children inherit genes from their parents, so the genetic information in an individual can be used to confirm or disprove that the individual is the biological parent of a child.","marks":"1","difficulty":"2"},{"id":"objective>Biology>1997>52","subject":"Biology","year":"1997","type":"Objective","topic":"BIOLOGY OF HEREDITY (GENETICS) : TRANSMISSION AND EXPRESSION OF CHARACTERISTICS IN ORGANISMS","question":"In which of the underlisted blood groupings is agglutination likely to occur during transfusion?  DONORRECEPIENTI toto TATAII TBTOTBTBIII TATATATB IV TATB totoV toto TBTB","images":[],"options":{"A":"I","B":"II","C":"III","D":"IV"},"answer":"D","explanation":"Agglutination, or clumping of cells, is likely to occur during a blood transfusion if the recipient's immune system recognizes the donor blood as foreign. This usually happens if the recipient has antibodies against the donor's blood type. In the given options, agglutination is likely to occur in option IV where the donor has blood type AB (TATB) and the recipient has blood type O (toto). This is because individuals with blood type O have both anti-A and anti-B antibodies, which will react with the A and B antigens on the red blood cells of the donor blood, causing agglutination.","marks":"1","difficulty":"3"},{"id":"objective>Biology>1997>53","subject":"Biology","year":"1997","type":"Objective","topic":"VARIATION IN POPULATION : MORPHOLOGICAL VARIATIONS","question":"Which of the following is not a morphological variation","images":[],"options":{"A":"Shape of nose","B":"Colour of skin","C":"Colour of eyes","D":"Tongue rolling"},"answer":"D","explanation":"Morphological variations refer to the observable physical differences between individuals of a species. These differences can be in size, shape, color, structure, etc. However, tongue rolling is not a morphological variation. It is a genetic trait that is inherited and does not affect the physical appearance of an individual.","marks":"1","difficulty":"1"},{"id":"objective>Biology>1997>54","subject":"Biology","year":"1997","type":"Objective","topic":"BIOLOGY OF HEREDITY (GENETICS) : CHROMOSOMES","question":"Which of the following is found in Meiosis but not in Mitosis?","images":[],"options":{"A":"Chromatids","B":"Prophase","C":"Crossing over","D":"Spindle fibres"},"answer":"C","explanation":"Meiosis and Mitosis are two types of cell division. The main difference between them is that Meiosis involves two rounds of genetic separation and cellular division while Mitosis only involves one of each. In the process of Meiosis, crossing over occurs during Prophase I, where homologous chromosomes pair up and exchange segments of their genetic material. This does not occur in Mitosis, hence the correct answer is 'Crossing over'.","marks":"1","difficulty":"2"},{"id":"objective>Biology>1997>55","subject":"Biology","year":"1997","type":"Objective","topic":"BIOLOGY OF HEREDITY (GENETICS) : LINKAGE, SEX DETERMINATION AND SEX LINKED CHARACTERS","question":"In man haemophilia is recessive and sex linked, The probability of carrier mother and a normal father having a haemophilic male is","images":[],"options":{"A":"1/4","B":"1/8","C":"2/3","D":"1/2"},"answer":"D","explanation":"Mother is a carrier(AS) and father is normal (AA) during test crossing the outcome are (AA,AA,AS,and AS) Probability=number of carrirer child divide by total outcome, i.e 2/4=1/2","marks":"1","difficulty":"2"},{"id":"objective>Biology>1997>56","subject":"Biology","year":"1997","type":"Objective","topic":"BIOLOGY OF HEREDITY (GENETICS) : APPLICATION OF THE PRINCIPLES OF HEREDITY","question":"In which of the following is the knowledge of genetics not applicable?","images":[],"options":{"A":"Development of high-yielding varieties","B":"Preservation of seeds","C":"Development of early maturing varieties","D":"Improvement in quality of yield"},"answer":"B","explanation":"Genetics is the study of genes, genetic variation, and heredity in living organisms. It is generally considered a field of biology, but intersects frequently with many other life sciences and is strongly linked with the study of information systems. The knowledge of genetics is applicable in the development of high-yielding varieties, development of early maturing varieties, and improvement in quality of yield as these all involve manipulation and understanding of genetic material. However, the preservation of seeds does not require the knowledge of genetics. It is more related to the field of botany and environmental science.","marks":"1","difficulty":"2"},{"id":"objective>Biology>1997>57","subject":"Biology","year":"1997","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL COMPONENTS","question":"In an inter-species competition, the less successful species usually","images":[],"options":{"A":"reproduce faster","B":"become more active","C":"become domant","D":"become eliminated"},"answer":"D","explanation":"In an inter-species competition, the less successful species usually become eliminated. This is due to the principle of competitive exclusion, which states that two species competing for the same resources cannot coexist if other ecological factors are constant. When one species has even the slightest advantage over another, the one with the advantage will dominate in the long term. This leads to the extinction of the less successful species.","marks":"1","difficulty":"1"},{"id":"objective>Biology>1997>58","subject":"Biology","year":"1997","type":"Objective","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.","question":"Which of the following characteristics distinguishes the soldier termite from other members of the caste?","images":[],"options":{"A":"Wingless, strong mandibles and large head","B":"Small head, small thorax and large abdomen","C":"Small head, Wingless, and small thorax","D":"Small head, winged and small thorax"},"answer":"A","explanation":"The soldier termite is distinguished from other members of the caste by its wingless nature, strong mandibles, and large head. These characteristics enable it to perform its primary role of colony defense. The strong mandibles are used for fighting off predators, the large head houses the muscles that power the mandibles, and being wingless is a common trait among all termites except reproductive ones.","marks":"1","difficulty":"2"},{"id":"objective>Biology>1997>59","subject":"Biology","year":"1997","type":"Objective","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.","question":"Bees communicate with one another to obtain information about the direction of food source through","images":[],"options":{"A":"complicated set of dances","B":"smell","C":"contract notes","D":"observation"},"answer":"A","explanation":"Bees communicate with each other about the location of food sources through a series of movements known as the 'waggle dance'. This dance involves a combination of circles and straight runs, with the bee 'waggling' its body during the straight runs. The direction of the straight run indicates the direction of the food source relative to the sun, while the duration of the waggle indicates the distance to the food source. Therefore, the correct answer is 'complicated set of dances'.","marks":"1","difficulty":"2"},{"id":"objective>Biology>1997>60","subject":"Biology","year":"1997","type":"Objective","topic":"EVOLUTION : ADAPTIVE COLOURATION","question":"Which of the following behavioural patterns describes adaptive colouration?","images":[],"options":{"A":"Counter shadding","B":"Hibernation","C":"Aestivation","D":"Aggregation"},"answer":"A","explanation":"Adaptive coloration is a type of camouflage where an organism's coloration allows it to blend in with its environment, making it harder for predators to see. Counter shading is a form of adaptive coloration where the upper side of an animal is darker than its underside. This helps to create an illusion of flatness, which can make the animal harder to detect in its environment. Therefore, the correct answer is 'Counter shading'.","marks":"1","difficulty":"2"}];